(self.webpackChunkcheatsheet=self.webpackChunkcheatsheet||[]).push([[7098],{8940:(t,a,r)=>{"use strict";r.r(a),r.d(a,{data:()=>e});const e={key:"v-1f49a4a2",path:"/spss/data/transform/",title:"Data Transformation",lang:"en-US",frontmatter:{},excerpt:"",headers:[{level:2,title:"Bootstrapping",slug:"bootstrapping",children:[]},{level:2,title:"Value Transformation",slug:"value-transformation",children:[]}],filePathRelative:"spss/data/transform/README.md",git:{updatedTime:162676698e4,contributors:[]}}},1459:(t,a,r)=>{"use strict";r.r(a),r.d(a,{default:()=>o});const e=(0,r(6252).uE)('<h1 id="data-transformation" tabindex="-1"><a class="header-anchor" href="#data-transformation" aria-hidden="true">#</a> Data Transformation</h1><h2 id="bootstrapping" tabindex="-1"><a class="header-anchor" href="#bootstrapping" aria-hidden="true">#</a> Bootstrapping</h2><p>การสุ่มตัวแปรมาอยู่ในกลุ่มใหม่ โดยการลองไปหลายๆครั้ง เพื่อให้ค่านื่งกว่าเดิม Analyze → Descriptive Statistics → Explore</p><p><strong>เหตุผลการทำ Bootstrapping</strong></p><ul><li>ทำเพื่อลด Standard Error + ปรับขนาด Confidence Intervals → ทำให้ Normal</li></ul><p><strong>ทำ Bootstrapping เมื่อ</strong></p><ul><li>ไม่รู้ประเภทการกระจายตัวของตัวแปร</li><li>ข้อมูลมีน้อยเกินไป</li><li>ไม่ผ่านการทดสอบ Normality / Homoscedacity</li></ul><p><strong>How to</strong> เลือกตัวแปรไปไว้ใน Dependent List → Bootstrap → กด Perform Bootstrapping → กด Bias corrected accelerated → กด Continue</p><h2 id="value-transformation" tabindex="-1"><a class="header-anchor" href="#value-transformation" aria-hidden="true">#</a> Value Transformation</h2><p>เพื่อให้ตัวแปรมีการกระจายแบบ Normal มากขึ้น</p><p>Transform → Compute Variable</p><table><thead><tr><th>Exponent Model</th><th>log(y)</th></tr></thead><tbody><tr><td>Quadratic Model</td><td>sqrt(y)</td></tr><tr><td>Reciprocal Model</td><td>1/y</td></tr></tbody></table><p>แล้วตั้งชื่อตัวแปรใหม่ ใน Target Variable</p>',13),o={render:function(t,a){return e}}}}]);